//////////////////////////////////////////////////////////////////////////////
// Register Interface for Core and JTAG side
//////////////////////////////////////////////////////////////////////////////
// SEC_CM: BUS.INTEGRITY
// SEC_CM: DEBUG_POLICY_VALID.CONFIG.SHADOW
// SEC_CM: DEBUG_POLICY_CATEGORY.CONFIG.SHADOW
soc_dbg_ctrl_core_reg_top u_core_reg (
  .clk_i,
  .rst_ni,
  .rst_shadowed_ni,
  .tl_i                   ( core_tl_i            ),
  .tl_o                   ( core_tl_o            ),
  .reg2hw                 ( core_reg2hw          ),
  .hw2reg                 ( core_hw2reg          ),
  .shadowed_storage_err_o ( shadowed_storage_err ),
  .shadowed_update_err_o  ( shadowed_update_err  ),
  .intg_err_o             ( core_tl_intg_err     )
);

prim_flop_2sync #(
  .Width      ( prim_mubi_pkg::MuBi4Width   ),
  .ResetValue ( {prim_mubi_pkg::MuBi4False} )
) u_sync_valid (
  .clk_i  ( clk_i                      ),
  .rst_ni ( rst_ni                     ),
  .d_i    ( soc_dbg_policy_bus_i.valid ),
  .q_o    ( {valid_sync}               )
);

prim_flop_2sync #(
  .Width      ( prim_mubi_pkg::MuBi4Width   ),
  .ResetValue ( {prim_mubi_pkg::MuBi4False} )
) u_sync_relocked (
  .clk_i  ( clk_i                         ),
  .rst_ni ( rst_ni                        ),
  .d_i    ( soc_dbg_policy_bus_i.relocked ),
  .q_o    ( {relocked_sync}               )
);

prim_flop_en #(
  .Width       ( $bits(soc_dbg_ctrl_pkg::dbg_category_e) ),
  .ResetValue  ( {soc_dbg_ctrl_pkg::DbgCategoryLocked}   )
) u_sampled_policy (
  .clk_i  ( clk_i                         ),
  .rst_ni ( rst_ni                        ),
  .en_i   ( valid_rising                  ),
  .d_i    ( soc_dbg_policy_bus_i.category ),
  .q_o    ( {debug_category_q}            )
);

prim_flop_en #(
  .Width      ( prim_mubi_pkg::MuBi4Width   ),
  .ResetValue ( {prim_mubi_pkg::MuBi4False} )
) u_delay_relock (
  .clk_i  ( clk_i         ),
  .rst_ni ( rst_ni        ),
  .en_i   ( valid_rising  ),
  .d_i    ( relocked_sync ),
  .q_o    ( {relocked_q}  )
);
